# config/shadow_config.py
from app.feature_flags import get_flag

def get_shadow_config():
    """Read shadow mode config from feature flags at request time."""
    return {
        # Master switch: deploy shadow infra without enabling traffic
        "enabled": get_flag("shadow_mode_enabled", default=False),
        # Fraction of requests to shadow (0.0–1.0)
        "sample_rate": get_flag("shadow_sample_rate", default=0.01),
        # Which model/prompt to use for shadow
        "model": get_flag("shadow_model_id", default="claude-haiku-4-5-20251001"),
        "prompt_version": get_flag("shadow_prompt_version", default="v2"),
    }

# In the main request handler:
def build_shadow_router(primary_client):
    cfg = get_shadow_config()
    if not cfg["enabled"]:
        return ShadowRouter(primary=primary_client, shadow=None, shadow_enabled=False)
    shadow_client = LLMClient(
        model=cfg["model"],
        prompt_version=cfg["prompt_version"],
    )
    return ShadowRouter(
        primary=primary_client,
        shadow=shadow_client,
        shadow_enabled=True,
        shadow_sample_rate=cfg["sample_rate"],
    )

