import numpy as np
from functools import lru_cache
from sentence_transformers import SentenceTransformer

# Load once at startup; this is the primary cost of the comparator
@lru_cache(maxsize=1)
def _embedding_model():
    return SentenceTransformer("all-MiniLM-L6-v2")

def semantic_similarity(response_a: str, response_b: str) -> float:
    """Return cosine similarity [0.0, 1.0] between two response strings."""
    model = _embedding_model()
    embeddings = model.encode([response_a, response_b], normalize_embeddings=True)
    # Cosine similarity of two unit vectors is just dot product
    return float(np.dot(embeddings[0], embeddings[1]))

def safety_flag_check(response: str) -> bool:
    """Return True if the response contains content that should be flagged."""
    # Replace with your production safety classifier
    BLOCKED_PATTERNS = [
        "personal information:",
        "here is the user's password",
        "social security number",
    ]
    lower = response.lower()
    return any(p in lower for p in BLOCKED_PATTERNS)

